+
+            // Relational / Comparison Operators
+            ops.add(Expression.make(BOOLEANS, "(", type, " == ", type, ")"));
+            ops.add(Expression.make(BOOLEANS, "(", type, " != ", type, ")"));
+            ops.add(Expression.make(BOOLEANS, "(", type, " > ",  type, ")"));
